mapper.sql:
select distinct null as `projectId`, pp.projectCode as `projectCode`, null as `rank`, ifnull(pp.projectName, p.projectName) as `projectName`, `fd`.`basicDataName` as `projectStateName`, `fd`.`basicDataId` as `projectState`, ifnull( `p`.`contractNo`, pp.projectCode ) as `contractNo`, ifnull(c1.id, c2.id) as compId, `pp`.`officeCode` as `officeCode`, `d`.`departmentName` as `officeName`, `pp`.`salesManCode` as `salesManCode`, `pp`.`salesManName` as `salesManName`, null as `projectStartTime`, null as projectCreateTime, `pp`.`systemName` as `systemName`, null as `serviceManager`, null as `serviceManagerName`, null as `projectManager`, null as `projectManagerName`, null as shipmentStateName, null as shipmentState, null as planStateName, null as projectPlanState, null as executionStateName, null as executionState, null as closeProcessStateName, null as closeProcessState, null as projectRefreshTime, null as projectCloseTime, null ssfs, null ssfsName, null partnerChannel, pp.projectType
from `pm_project_property_af_from_sms` `pp` left join `pm_order_data_from_sap` `p` on `p`.`orderExecNumber` = `pp`.`orderExecNumber` left join `view_distinct_contract` `v` on `v`.`id` = `p`.`id` left join `fnd_department` `d` on `pp`.`officeCode` = `d`.`departmentNum` left join `fnd_basic_data` `fd` on `fd`.`basicDataId` = '10' and `fd`.`dataTypeCode` = '02' and `fd`.`effectiveFrom` < now() and ( `fd`.`effectiveTo` > now() or isnull(`fd`.`effectiveTo`) ) left join fnd_company c1 on c1.code = p.compCode left join fnd_company c2 on c2.`code` = pp.corporationCode
where
pp.`projectType` = 'afss'
and pp.projectType = #{model.projectType}
AND pp.projectCode like concat("%", #{model.projectCode, jdbcType=VARCHAR}, "%")
AND IFNULL(pp.projectName, p.projectName) like concat("%", #{model.projectName, jdbcType=VARCHAR}, "%") AND
AND pp.officeCode = #{model.column001, jdbcType=VARCHAR}
AND pp.marketName = #{model.column004, jdbcType=VARCHAR}
AND pp.systemName = #{model.column005, jdbcType=VARCHAR}
AND pp.expendName = #{model.column006, jdbcType=VARCHAR}
AND pp.industryName = #{model.column007, jdbcType=VARCHAR}
AND #{model.compId, jdbcType=INTEGER} = IFNULL(c1.id, c2.id)
AND ( projectCode like CONCAT("%", #{fuzzy}, "%") or projectName like CONCAT("%", #{fuzzy}, "%") or )
and not exists (select 1 from `pm_project_contract` `t1` join `pm_project_group_relationship` `t2` on `t1`.`projectGroupCode` = `t2`.`projectGroupCode` join `pm_project_header` `t3` on ( `t2`.`projectCode` = `t3`.`projectCode` or `t3`.`projectCode` = replace(`t2`.`projectCode`, "-his", "") ) and `t3`.`effectiveFrom` <= now() and ( `t3`.`effectiveTo` > now() or isnull(`t3`.`effectiveTo`) ) where t3.`projectType` = pp.`projectType` and ( ( `v`.`contractNo` = `t1`.`contractNo` and v.contractNo is not null ) )) and v.`contractNo` is not null union select distinct null as `projectId`, pp.projectCode as `projectCode`, null as `rank`, ifnull( if( p.salesType = '01', p.projectName, pp.projectName ), p.projectName ) as `projectName`, `fd`.`basicDataName` as `projectStateName`, `fd`.`basicDataId` as `projectState`, ifnull( `p`.`contractNo`, pp.orderExecNumber ) as `contractNo`, ifnull(c1.id, c2.id) as compId, `pp`.`officeCode` as `officeCode`, `d`.`departmentName` as `officeName`, `pp`.`salesManCode` as `salesManCode`, `pp`.`salesManName` as `salesManName`, null as `projectStartTime`, null as projectCreateTime, `pp`.`systemName` as `systemName`, null as `serviceManager`, null as `serviceManagerName`, null as `projectManager`, null as `projectManagerName`, null as shipmentStateName, null as shipmentState, null as planStateName, null as projectPlanState, null as executionStateName, null as executionState, null as closeProcessStateName, null as closeProcessState, null as projectRefreshTime, null as projectCloseTime, null ssfs, null ssfsName, null partnerChannel, pp.projectType from `pm_project_property_af_from_sms` `pp` left join `pm_order_data_from_sap` `p` on `p`.`orderExecNumber` = `pp`.`orderExecNumber` left join `view_distinct_contract` `v` on `v`.`id` = `p`.`id` left join `fnd_department` `d` on `pp`.`officeCode` = `d`.`departmentNum` left join `fnd_basic_data` `fd` on `fd`.`basicDataId` = '10' and `fd`.`dataTypeCode` = '02' and `fd`.`effectiveFrom` < now() and ( `fd`.`effectiveTo` > now() or isnull(`fd`.`effectiveTo`) ) left join fnd_company c1 on c1.code = p.compCode left join fnd_company c2 on c2.`code` = pp.corporationCode
where
pp.`projectType` = 'afxx'
and pp.projectType = #{model.projectType}
AND pp.projectCode like concat("%", #{model.projectCode, jdbcType=VARCHAR}, "%")
AND IFNULL(pp.projectName, p.projectName) like concat("%", #{model.projectName, jdbcType=VARCHAR}, "%") AND
AND pp.officeCode = #{model.column001, jdbcType=VARCHAR}
AND pp.marketName = #{model.column004, jdbcType=VARCHAR}
AND pp.systemName = #{model.column005, jdbcType=VARCHAR}
AND pp.expendName = #{model.column006, jdbcType=VARCHAR}
AND pp.industryName = #{model.column007, jdbcType=VARCHAR}
AND #{model.compId, jdbcType=INTEGER} = IFNULL(c1.id, c2.id)
AND ( projectCode like CONCAT("%", #{fuzzy}, "%") or projectName like CONCAT("%", #{fuzzy}, "%") or )
and not exists (select 1 from `pm_project_contract` `t1` join `pm_project_group_relationship` `t2` on `t1`.`projectGroupCode` = `t2`.`projectGroupCode` join `pm_project_header` `t3` on ( `t2`.`projectCode` = `t3`.`projectCode` or `t3`.`projectCode` = replace(`t2`.`projectCode`, "-his", "") ) and `t3`.`effectiveFrom` <= now() and ( `t3`.`effectiveTo` > now() or isnull(`t3`.`effectiveTo`) ) where t3.`projectType` = pp.`projectType` and pp.`orderExecNumber` = t1.`contractNo`)

mapper.select:
select t1.basicDataName as column012, pppfs.projectType, pppfs.objId as relateId, pppfs.channelName as agentChannel,
ifnull(podfs.contractNo, pppfs.projectCode) as contractNo, case when pppfs.projectCode is null then podfs.contractNo else pppfs.projectCode end as projectCode, ifnull(if(podfs.salesType = '01', podfs.projectName, pppfs.projectName), podfs.projectName) as projectName, podfs.orderCreateTime column009, podfs.customerCode column002, podfs.customerName column003, pppfs.salesManCode salesManCode, pppfs.salesManName salesManName, pppfs.marketCode marketCode, pppfs.marketName column004, pppfs.systemId systemId, pppfs.systemName column005, pppfs.expendId expendId, pppfs.expendName column006, pppfs.industryId, pppfs.industryName column007, pppfs.officeCode column001, fd.departmentName officeName, ppm.memberCode serviceManagerCode, ppm.memberName serviceManagerCodeforjson, pph.column008 column008, pph.column010 column010, pph.column011 column011, pph.column012 column012, IFNULL(t1.basicDataName, -1) as column012Readonly, pph.column013 column013, ifnull(podfs.compCode, pppfs.corporationCode) as compCode, ifnull(c.id, c1.id) as compId, ifnull(podfs.salesType, pppfs.projectType) as salesType, pppfs.projectMoney as smsProjectAmont, pppfs.projectCode as smsProjectCode, pppfs.submitTime as smsSubmitTime, pppfs.orderExecNumber as smsOrderExecNumber
from pm_project_property_af_from_sms pppfs left join pm_order_data_from_sap podfs on podfs.orderExecNumber = pppfs.orderExecNumber left join pm_project_header pph on podfs.contractNo = pph.projectCode and pppfs.projectType = pph.projectType left join fnd_department fd on fd.departmentNum = pppfs.officeCode left join pm_project_member ppm on pph.projectId = ppm.projectId and ppm.effectiveFrom <= now() and (ppm.effectiveTo > now() or ppm.effectiveTo is null) left join fnd_basic_data t1 on pppfs.serviceTypeName = t1.basicDataId and t1.dataTypeCode = 21 and t1.effectiveFrom <= now() and ( t1.effectiveTo > now() or t1.effectiveTo is null ) left join fnd_company c on c.code = podfs.compCode left join fnd_company c1 on c1.code = pppfs.corporationCode
where pppfs.projectType = #{projectType}
and pppfs.projectCode = #{contractNo}
and podfs.contractNo = #{contractNo}
order by podfs.id desc limit 1
